sql:
SELECT team_id, COUNT(player_id) AS player_count
FROM rosters
GROUP BY team_id;

SELECT AVG(roster_percentage) AS average_roster_percentage
FROM players
WHERE status = 'active' AND position IN ('WR', 'RB', 'TE');

external_knowledge:
- "lit up the fantasy world" refers to players scoring the highest in fantasy points; 
- "shining stars" metaphorically refers to the top-performing players; 
- "games that have come to a close" refers to games with a 'completed' status.

- 'active' status indicates the player is currently participating in the league;
- 'rostered' means the player is officially part of the team's active roster;
- 'injuries' refers to the records of injuries a player has suffered during their career.

sql:
SELECT player_id, AVG(transfer_id) AS average_transfers
FROM transfers
GROUP BY player_id;
